WebLink.url:
{!REQUIRESCRIPT("/soap/ajax/57.0/connection.js")}

var ids = {!GETRECORDIDS($ObjectType.sirenum__Ticket__c)};

if (!ids || ids.length === 0) {
  alert('Please select at least one Ticket.');
} else {
  if (confirm('Delete ' + ids.length + ' selected Ticket record(s)? This cannot be undone.')) {
    try {
      // Bulk delete; returns an array of SaveResult
      var results = sforce.connection.deleteIds(ids);
      var errors = [];
      for (var i = 0; i < results.length; i++) {
        if (!results[i].success) {
          errors.push('Row ' + (i+1) + ': ' + results[i].errors[0].message);
        }
      }
      if (errors.length > 0) {
        alert('Some Tickets were not deleted:\n' + errors.join('\n'));
      }
      // Refresh the list view after delete
      window.location.reload();
    } catch (e) {
      alert('Unexpected error: ' + (e && e.message ? e.message : e));
    }
  }
}
